head.script:
scwin.initData = {
	"chart" : {
		"chartUnit" : 10,
		"chartIntervalCount" : 5,
		"rqtyDisplayLabel" : {
			"lgwtpw" : "대수력",
			"smlhp" : "소수력",
			"tdpw" : "조력",
			"wdpw" : "풍력",
			"snpw" : "태양광"
		},
		"dsqtyDisplayLabel" : {
			"itkpl" : "취수시설",
			"prnplc" : "가압시설",
			"fltplt" : "정수시설",
			"buld" : "건물",
			"dam" : "댐시설",
			"trnsp" : "수송",
			"etc" : "기타"
		}
	},
	"observeEvent" : false
};

/**
 * 화면 초기화에 필요한 로직을 수행한다.
 * @param
 * @return
 */
scwin.initScreen = function() {
	// 화면초기화 공통 함수 호출
	comLib.initForm($p, "ECSEC4100000", {"initScreenCallback" : scwin.searchDatas});
	// ecsLib.setChartResizeObserver(this);
};

/**
 * 화면 초기 데이터들을 조회한다.
 * @param
 * @return
 */
scwin.searchDatas = function() {
	// 조회조건 초기 설정
	scwin.initSearchParam();
	// 화면 데이터 조회
	scwin.btnInqire_onclick();
};

/**
 * 조회조건 초기화에 필요한 로직을 수행한다.
 * @param
 * @return
 */
scwin.initSearchParam = function() {
	var endDt = utilLib.getCurrentDate("yyyyMM");
	var basinCd = "ALL";

	var params = $p.getParameter("param");
	if (params) {
		if (params.ym) {
			endDt = String(params.ym);
			//today = String(params.ym) + "1231";
		}
		if (params.basinCd) {
			basinCd = params.basinCd;
			acbBasin.setValue(basinCd);
		}
	}
	var strtDt = endDt.substr(0, 4) + "01";

	dmaSearchParam.set("strtDt", strtDt);
	dmaSearchParam.set("endDt", endDt);
	dmaSearchParam.set("basinCd", basinCd);
	dmaSearchParam.set("deptCd", "ALL");
};

/**
 * 조회조건에 맞게 data를 조회한다.
 * @param
 * @return
 */
scwin.btnInqire_onclick = function() {
	var strtDate = dmaSearchParam.get("strtDt");
	var endDate = dmaSearchParam.get("endDt");
	var ecsBasinDivCd = dmaSearchParam.get("basinCd");
	var ecsChrgDeptId = dmaSearchParam.get("deptCd");

	if (String(strtDate).length != 6 || String(endDate).length != 6) {
		// 조회기간이 올바르지 않습니다.
		alert(utilLib.getMessage("ECS.INFO.00011")[0]);
		return;
	} else if (utilLib.minusMonths(strtDate, endDate) > 12 ? true : false) {
		// 조회기간은 {0}을 넘어갈 수 없습니다. 다시 설정해 주세요.
		alert(utilLib.getMessage("ECS.INFO.00012", "12개월")[0]);
		return;
	} else if (parseInt(strtDate) > parseInt(endDate)) {
		// 시작년월이 종료년월일보다 클수 없습니다.
		alert(utilLib.getMessage("ECS.INFO.00014")[0]);
		return;
	}

	var queryString = `?strtDt=${strtDate}`;
	queryString += `&endDt=${endDate}`;
	queryString += `&ecsBasinDivCd=${ecsBasinDivCd}`;
	queryString += `&ecsChrgDeptId=${ecsChrgDeptId}`;

	var option = {
		action : "ec/energyacmsltmng/cbnntrlt/retrieve-cbn-ntrlt.do"
			+ queryString,
		method : "get",
		resData : dltCbnntrltList,
		success : "scwin.inqireCallback",
		isShowMeg : false
	};
	ajaxLib.executeAjax($p, option);
};

/**
 * 조회 CallBack 실행한다.
 * @param
 * @return
 */
scwin.inqireCallback = function() {
	spnTotalRow.setValue(dltCbnntrltList.getRowCount());
	// 탄소 감축량 차트 생성
	scwin.searchChartRqty();
	// 탄소 배출량 차트 생성
	scwin.searchChartDsqty();
};

//============================================================================================
// 차트
//============================================================================================
/**
 * 탄소 감축량 차트를 생성
 */
scwin.searchChartRqty = function() {
	var chartVars = "rMateOnLoadCallFunction=" + $p.id + "scwin.chartReadyHandlerRqty";
	rMateChartH5.create($p.id + "chartRqty", grpChartRqty.getID(), chartVars, "100%", "100%");
};

/**
 * 탄소 감축량 차트 설정
 */
scwin.chartReadyHandlerRqty = function(id) {
	var rqtyData = dltCbnntrltList.getAllJSON();
	var titleObj = {};
	titleObj.lgwtpw = rqtyData.reduce((sum, obj) => sum += Number(obj.lgwtpw), 0);
	titleObj.smlhp = rqtyData.reduce((sum, obj) => sum += Number(obj.smlhp), 0);
	titleObj.tdpw = rqtyData.reduce((sum, obj) => sum += Number(obj.tdpw), 0);
	titleObj.wdpw = rqtyData.reduce((sum, obj) => sum += Number(obj.wdpw), 0);
	titleObj.snpw = rqtyData.reduce((sum, obj) => sum += Number(obj.snpw), 0);

	var maxData = Math.max(...Object.values(titleObj));

	titleObj.total =  ecsLib.dsplZeroFrmt(rqtyData.reduce((sum, obj) => sum += Number(obj.rqtySum), 0));

	var chartList = [];
	for (var key in scwin.initData.chart.rqtyDisplayLabel) {
		var name =  scwin.initData.chart.rqtyDisplayLabel[key];
		// var rqty =  rqtyData.reduce((sum, obj) => obj.key ? sum + Number(obj.key) : sum, 0) || 0;
		var rqty =  titleObj[key];
		chartList.push({
				"name" : name,
				"rqty" : rqty
		});
	};

	var chartUnit = Math.max(scwin.initData.chart.chartUnit, Math.pow(10, String(maxData.toFixed(0)).length - 2));
	var interval = Math.ceil((maxData / scwin.initData.chart.chartIntervalCount) / chartUnit) * chartUnit;

	var fillColor = "#30A744";
	var captionSpan = "&lt;span style=&quot;color:" + fillColor + ";&quot;&gt;" + titleObj.total + "&lt;/span&gt;";
	var captionSpan2 = "&lt;span style=&quot;font-size:0.7rem; color:" + fillColor + "; margin-left: -0.2rem;&quot;&gt;tCO2&lt;/span&gt;";
	var layoutStr =
		'<rMateChart backgroundColor="#FFFFFF" cornerRadius="12">'
		+ '	<Options>'
		+ '		<Caption text="Total ' + captionSpan + ' ' + captionSpan2 + ' 온실가스 감축량" textAlign="right" paddingTop="8" paddingRight="8" paddingBottom="8" fontWeight="bold" />'
		+ '		<Legend />'
		+ '	</Options>'
		+ '	<NumberFormatter id="numFmt" useThousandsSeparator="true" />'
		+ '	<Column2DChart showDataTips="true" dataTipDisplayMode="axis" maxColumnWidth="25">'
		+ '		<horizontalAxis>'
		+ '			<CategoryAxis categoryField="name" />'
		+ '		</horizontalAxis>'
		+ '		<verticalAxis>'
		+ '			<LinearAxis id="vAxis" interval="' + interval + '" formatter="{numFmt}" title="tCO2"/>'
		+ '		</verticalAxis>'
		+ '		<series>'
		+ '			<Column2DSeries color="#666666" labelPosition="outside" fontWeight="bold" yField="rqty" displayName="탄소 감축량(tCO2)">'
		+ '				<fill>'
		+ '					<SolidColor color="' + fillColor + '"/>'
		+ '				</fill>'
		+ '				<showDataEffect>'
		+ '					<SeriesInterpolate />'
		+ '				</showDataEffect>'
		+ '			</Column2DSeries>'
		+ '			</series>'
		+'		<verticalAxisRenderers>'
		+'			<Axis2DRenderer axis="{vAxis}" placement="left" verticalAxisTitleAlignment="vertical" titleGap="0" canDropLabels="false" showLine="false"/>'
		+'		</verticalAxisRenderers>'
		+ '	</Column2DChart>'
		+ '</rMateChart>';

	document.getElementById(id).setLayout(layoutStr);
	document.getElementById(id).setData(chartList);
};

/**
 * 탄소 배출량 차트를 생성
 */
scwin.searchChartDsqty = function() {
	var chartVars = "rMateOnLoadCallFunction=" + $p.id + "scwin.chartReadyHandlerDsqty";
	rMateChartH5.create($p.id + "chartDsqty", grpChartDsqty.getID(), chartVars, "100%", "100%");
};

/**
 * 탄소 배출량 차트 설정
 */
scwin.chartReadyHandlerDsqty = function(id) {
	var dsqtyData = dltCbnntrltList.getAllJSON();
	var titleObj = {};
	titleObj.itkpl = dsqtyData.reduce((sum, obj) => sum += Number(obj.itkpl), 0);
	titleObj.prnplc = dsqtyData.reduce((sum, obj) => sum += Number(obj.prnplc), 0);
	titleObj.fltplt = dsqtyData.reduce((sum, obj) => sum += Number(obj.fltplt), 0);
	titleObj.buld = dsqtyData.reduce((sum, obj) => sum += Number(obj.buld), 0);
	titleObj.trnsp = dsqtyData.reduce((sum, obj) => sum += Number(obj.trnsp), 0);
	titleObj.dam = dsqtyData.reduce((sum, obj) => sum += Number(obj.dam), 0);
	titleObj.etc = dsqtyData.reduce((sum, obj) => sum += Number(obj.etc), 0);

	var maxData = Math.max(...Object.values(titleObj));

	// titleObj.total = new Intl.NumberFormat("ko-KR").format(itkpl + prnplc + fltplt + buld + trnsp + dam + etc);
	titleObj.total = ecsLib.dsplZeroFrmt(dsqtyData.reduce((sum, obj) => sum += Number(obj.dsqtySum), 0));
	// var total = chartData[0].dsqtySum + chartData[1].dsqtySum + chartData[2].dsqtySum + chartData[3].dsqtySum + chartData[4].dsqtySum ;
	var chartList = [];
	for (var key in scwin.initData.chart.dsqtyDisplayLabel) {
		var name =  scwin.initData.chart.dsqtyDisplayLabel[key]
		// var dsqty =  dsqtyData.reduce((sum, obj) => obj.key ? sum + Number(obj.key) : sum, 0) || 0;
		var dsqty =  titleObj[key];
		chartList.push({
				"name" : name,
				"dsqty" : dsqty
		});
	};

	var chartUnit = Math.max(scwin.initData.chart.chartUnit, Math.pow(10, String(maxData.toFixed(0)).length - 2));
	var interval = Math.ceil((maxData / scwin.initData.chart.chartIntervalCount) / chartUnit) * chartUnit;

	var fillColor = "#E67780";
	var captionSpan = "&lt;span style=&quot;color:" + fillColor + ";&quot;&gt;" + titleObj.total + "&lt;/span&gt;";
	var captionSpan2 = "&lt;span style=&quot;font-size:0.7rem; color:" + fillColor + "; margin-left: -0.2rem;&quot;&gt;tCO2&lt;/span&gt;";
	var layoutStr =
		'<rMateChart backgroundColor="#FFFFFF" cornerRadius="12">'
		+ '	<Options>'
		+ '		<Caption text="Total ' + captionSpan + ' ' + captionSpan2 + ' 온실가스 배출량" textAlign="right" paddingTop="8" paddingRight="8" paddingBottom="8" fontWeight="bold" />'
		+ '		<Legend />'
		+ '	</Options>'
		+ '	<NumberFormatter id="numFmt" useThousandsSeparator="true" />'
		+ '	<Column2DChart showDataTips="true" dataTipDisplayMode="axis" maxColumnWidth="25">'
		+ '		<horizontalAxis>'
		+ '			<CategoryAxis categoryField="name" />'
		+ '		</horizontalAxis>'
		+ '		<verticalAxis>'
		+ '			<LinearAxis id="vAxis" interval="' + interval + '" formatter="{numFmt}" title="tCO2"/>'
		+ '		</verticalAxis>'
		+ '		<series>'
		+ '			<Column2DSeries color="#666666" labelPosition="outside" fontWeight="bold" yField="dsqty" displayName="탄소 배출량(tCO2)">'
		+ '				<fill>'
		+ '					<SolidColor color="' + fillColor + '" />'
		+ '				</fill>'
		+ '				<showDataEffect>'
		+ '					<SeriesInterpolate />'
		+ '				</showDataEffect>'
		+ '			</Column2DSeries>'
		+ '		</series>'
		+'		<verticalAxisRenderers>'
		+'			<Axis2DRenderer axis="{vAxis}" placement="left" verticalAxisTitleAlignment="vertical" titleGap="0" canDropLabels="false" showLine="false"/>'
		+'		</verticalAxisRenderers>'
		+ '	</Column2DChart>'
		+ '</rMateChart>';

	document.getElementById(id).setLayout(layoutStr);
	document.getElementById(id).setData(chartList);
};

/**
 * 조회박스 선택별 값을 세팅한다.
 * @param info
 * @return
 */
scwin.acbBasin_onviewchange = function(info) {
	var ecsBasinDivCd = info.newValue;
	dmaSearchParam.set("basinCd", ecsBasinDivCd);

	var queryString = `?ecsBasinDivCd=${ecsBasinDivCd}`;
	var option = {
		action : "zz/cmmn/retrieve-cnsmp-cnd-dept.do"
			+ queryString,
		method : "get",
		resData : dltAutoCondition2,
		success : "",
		isShowMeg : false
	};
	ajaxLib.executeAjax($p, option);
	dmaSearchParam.set("deptCd", "ALL");
};

scwin.acbDept_onviewchange = function(info) {
	dmaSearchParam.set("deptCd", info.newValue);
};

/**
 * 그리드 합계 소수점 첫째자리까지 표시 한다.
 * @param value
 * @return
 */
scwin.dsplFrmt = function(value) {
	return ecsLib.dsplFrmt(value, 1);
};

// 중립율 계산_240123
scwin.fAcmtrtCalc = function() {
	var fDsqtySumData = grdCbnntrltList.getFooterData("fDsqtySum");
	var fRqtySumData = grdCbnntrltList.getFooterData("fRqtySum");
	return fRqtySumData / fDsqtySumData * 100;
};

//============================================================================================
// 엑셀
//============================================================================================
/**
 * 그리드의 내용을 엑셀로 다운로드 한다.
 * @return
 */
scwin.btnDownExcel_onclick = function() {
	var menuNm = $p.getComponentById("wfm_title").scope.$p.getComponentById("tbxScreenTitle").getValue();
	// 엑셀 내부 타이틀 추가_240105
	var infoArr = [];
	var infoObj = {
		rowIndex 	: 0,
		colIndex 	: 0,
		rowSpan 	: 0,
		colSpan 	: 16,
		text 		: `${menuNm}`,
		textAlign 	: "left"
	};
	infoArr.push(infoObj);

	comLib.downloadExcel(grdCbnntrltList, {
		fileName : `${menuNm}.xlsx`,
		type : 1,
		autoSizeColumn : true,
		useDataFormat : true,
		applyDataFormat : true,
		decimal : "auto"
	}, infoArr);
};
